import { AfterViewInit, Component, ElementRef, OnInit, ViewChild, Inject } from '@angular/core';
import { MatDialog as MatDialog, MatDialogRef as MatDialogRef, MAT_DIALOG_DATA as MAT_DIALOG_DATA } from '@angular/material/dialog';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar } from '@angular/material/snack-bar';
import { UntypedFormBuilder, UntypedFormGroup, Validators, FormControl, FormGroupDirective, NgForm } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { MatTableDataSource } from '@angular/material/table';
export interface DialogData {
  col_id: any;
  ref_id: any;
  moduleName: any;
  vendor_id: any;
}
export interface logData {
  Name: any;
  actionType: any;
  oldValue: any;
  newValue: any;
  actionDate: any
}

@Component({
    selector: 'auditLog',
    templateUrl: 'auditLog.component.html',
    styleUrls: ['auditLog.component.scss'],
    standalone: false
})
export class AuditLogComponent {
  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;
  form: UntypedFormGroup;
  logAudit = false
  dataSource: MatTableDataSource<logData>;
  exceedsMaxrows = false;
  displayedColumns: string[] = ['Name', 'Date', 'newValue', 'oldValue'];
  logs: any[] = [];
  constructor(private itemService: itemService, public dialogRef: MatDialogRef<AuditLogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: DialogData, public dialog: MatDialog, private _snakcbar: MatSnackBar, private fb: UntypedFormBuilder) {
  }
  ngAfterViewInit() {

  }
  ngOnInit() {

    this.itemService.getAuditLog({ ref_id: this.data.ref_id, moduleName: ['RFQVendor', 'RFQItem', 'rfq_detail'],  isPriceLog: true}).subscribe((res: any) => {
      if (res.status == 200) {
        let  transformedData = res.data
          .map((row: any) => {
            let oldValue: number | null = null;
            let newValue: number | null = null;
            let oldObj: any = {};
            let newObj: any = {};

            try {
              oldObj = row.oldValue ? JSON.parse(row.oldValue) : {};
              newObj = row.newValue ? JSON.parse(row.newValue) : {};

              oldValue =
                oldObj?.RFQVendor_amount !== undefined && oldObj?.RFQVendor_amount !== null
                  ? Number(oldObj.RFQVendor_amount)
                  : null;

              newValue =
                newObj?.RFQVendor_amount !== undefined && newObj?.RFQVendor_amount !== null
                  ? Number(newObj.RFQVendor_amount)
                  : null;
            } catch (e) {
            }

            return {
              username: row.username,
              oldObj,
              newObj,
              oldValue,
              newValue,
              actionDate: row.actionDate
            };
          })
          .filter(row => {
            const oldObj = row.oldObj || {};
            const newObj = row.newObj || {};

            // Check if vendor amount changed
            const amountChanged = (oldObj.RFQVendor_amount ?? null) !== (newObj.RFQVendor_amount ?? null);

            return amountChanged;
          });

          // ✅ Deduplicate consecutive same values per user
          transformedData = transformedData.filter((item, index, arr) => {
            if (index === 0) return true;
            const prev = arr[index - 1];
            return !(prev.username === item.username && prev.newValue === item.newValue);
          });

          // Sort by date (newest first), then username for stable ordering
          transformedData.sort((a, b) => {
            const dateA = new Date(a.actionDate).getTime();
            const dateB = new Date(b.actionDate).getTime();
            if (dateB !== dateA) return dateB - dateA;
            return (a?.username ?? '').localeCompare(b?.username ?? '');
          });

        this.dataSource = new MatTableDataSource(transformedData);
        this.dataSource.sortingDataAccessor = (row: any, sortHeaderId: string) => {
          switch (sortHeaderId) {
            case 'Name':
              return row.username ?? '';
            case 'Date':
              return new Date(row.actionDate).getTime();
            case 'newValue':
              return row.newValue ?? '';
            case 'oldValue':
              return row.oldValue ?? '';
            default:
              return '';
          }
        };
        this.dataSource.paginator = this.paginator;
        this.dataSource.sort = this.sort;
      }
    });
  }

  onSave() {
    //percent = (parseFloat(percent) / 100).toFixed(2);
    //   let duty_rate = ((parseFloat(this.data.fob_cost) * (parseFloat(percent) + 1)) + parseFloat(dollar)).toFixed(2);
    if (this.form.status == "VALID") {
      this.dialogRef.close({ duty_rate: this.form.value.percentAmount, duty_rate_dollar_amount: this.form.value.dollarAmount })
    } else {
      this._snakcbar.open('Please fill all fields', 'close');
    }
  }

  onClose() {
    this.dialogRef.close()
  }

}

