const { getContext } = require('../helpers/context.middleware');

const AuditService = {};

AuditService.log = async (models, actionType, model, ref_id_fk, newValue, oldValue, element_id = null) => {
    const context = getContext();
    const user = context ? context.user : null;

    if (!user) {
        return;
    }

    try {
        await models.AuditLog.create({
            newValue: newValue ? newValue.toString() : null,
            oldValue: oldValue ? oldValue.toString() : null,
            username: user.name || user.email,
            actionType: actionType,
            actionDate: new Date(),
            user_id_fk: user.user_id,
            moduleName: model.name,
            ref_id_fk: ref_id_fk,
            element_id: element_id
        });
    } catch (error) {
        console.error("Failed to write to audit log:", error);
    }
};

module.exports = AuditService;

