Customer.getAuditLog = async (req, result) => {

  let condition = {};

  if (Object.keys(req.body).length > 0) {
    if (req.body.moduleName) {
      condition.moduleName = req.body.moduleName;
    }
    if (req.body.ref_id) {
      condition.ref_id_fk = req.body.ref_id;
    }
    if (req.body.element_id) {
      condition.element_id = req.body.element_id;
    }
    if (req.body.vendor_id) {
      condition.user_id_fk = req.body.vendor_id;
    }
  }

  // 👉 Default: restrict to current month
  let dateCondition = null;

  if (!req.body.isPriceLog) {
    const now = new Date();
    const currentMonthStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const currentMonthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59, 999);

    dateCondition = {
      [Op.between]: [currentMonthStart, currentMonthEnd]
    };
  }

  await sql.AuditLog.findAll({
    order: [['id', 'DESC']],
    logging: console.log,
    where: {
      ...condition,
      ...(dateCondition ? { actionDate: dateCondition } : {}) // ✅ Only apply if not isPriceLog
    }
  })
  .then((data) => {
    result(null, { data: data, status: 200 });
  })
  .catch(err => {
    result(err, null);
  });
};

Customer.saveLog = async (req, result) => {
  let user_info = await getUserInfo(req.headers.authorization)
  if (user_info.role == 'vendor') {
    vendor_info = await findVendorInfoWithEmail(user_info)
    user_info.user_id = vendor_info.factory_id_fk
  }
  await sql.AuditLog.create({
    username: user_info.name,
    user_id_fk: user_info.user_id,
    oldValue: req.body.oldValue,
    newValue: req.body.newValue,
    element_id: req.body.col_id,
    moduleName: req.body.moduleName,
    ref_id_fk: req.body.ref_id,
    actionDate: new Date().toISOString(),
  }).then(async (data) => {
    result(null, { data: data, status: 200 });
  }).catch(err => {
    result(err, null);
  })
}
Customer.newCBM = async (req, result) => {
  await sql.RFQContainer.create({
    RFQContainer_price: req.body.title,
  })
    .then(data => {
      if (data) {
        result(null, data);
      }
    }).catch(err => {
      result(err, null);
    });
}
Customer.saveTechLink = async (req, sharedLink) => {
  const { item_num_id_fk,
    attachment_type,
    attachment_display_name,
    fileName, comment_id, uuid, primary_image } = req.body
  const companyCode_name = 'EDGEHOME'
  const divisionCode_name = 'CW001'
  const item_attachment_resourceId = 1

  try {
    if (req.body.flag === 'rfq-update') {
      const rfqItem = await sql.RFQItem.findOne({ where: { rfqItem_id: req.params.id } });
      if (rfqItem) {
        await rfqItem.update({ rfqItem_tech_pack_link: sharedLink });
      }

    } else if (req.body.flag === 'comment-create-edit') {
      return await sql.itemAttachment.create({
        item_num_id_fk,
        attachment_type,
        attachment_display_name,
        attachment_link: sharedLink,
        item_attachment_fileName: fileName,
        companyCode_name,
        divisionCode_name,
        item_attachment_resourceId,
        comment_id
      })
    } else if (req.body.flag === 'item-attachment-create') {
      return await sql.itemAttachment.create({
        item_num_id_fk,
        attachment_type,
        attachment_display_name,
        attachment_link: sharedLink,
        item_attachment_fileName: fileName,
        companyCode_name,
        divisionCode_name,
        item_attachment_resourceId
      })
    } else if (req.body.flag === 'item-attachment-update-uuid') {
      const attachment = await sql.itemAttachment.findOne({
        where: {
          [Op.and]: [{ item_num_id_fk: item_num_id_fk }, {
            item_attachment_fileName: { [Op.like]: `%${fileName}%` }
          }]
        }
      });
      if (attachment) {
        return await attachment.update({ uuid, primary_image });
      }
    } else if (req.body.flag === 'image-thumbnail-create') {
      return await sql.itemAttachment.create({
        item_num_id_fk,
        attachment_type,
        attachment_display_name,
        attachment_link: sharedLink,
        item_attachment_fileName: fileName,
        companyCode_name,
        divisionCode_name,
        item_attachment_resourceId,
        uuid
      })
    }

  } catch (e) {
  }
}

