232	    const changes = [];
233	
234	    if (this.isObject(oldObj) && this.isObject(newObj)) {
235	      const allKeys = [...new Set([...Object.keys(oldObj), ...Object.keys(newObj)])];
236	      allKeys.forEach(key => {
237	        let oldValue = oldObj[key];
238	        let newValue = newObj[key];
