          this.logs = res.data.map(log => {
            const oldVal = this.parseJson(log.oldValue);
            const newVal = this.parseJson(log.newValue);
            const changes = this.getChanges(oldVal, newVal, log);
            return { ...log, oldValue: oldVal, newValue: newVal, changes };
          });

          const firstLog = this.logs[0];

          const creationLog = [...this.logs].reverse().find(log => log.moduleName === 'RFQItem');

