        if (key === 'rfqItem_step') {
          oldValue = this.stepMappings[oldValue] || oldValue;
          newValue = this.stepMappings[newValue] || newValue;
        }

        if (key === 'rfqItem_active') {
          oldValue = this.statusMappings[oldValue] || oldValue;
          newValue = this.statusMappings[newValue] || newValue;
        }

        if (key === 'req_status') {
          oldValue = this.reqStatusMappings[oldValue] || oldValue;
          newValue = this.reqStatusMappings[newValue] || newValue;
        }

        if (key === 'rfqItem_rfq_group') {
          oldValue = this.rfqGroupMappings[oldValue] || oldValue;
          newValue = this.rfqGroupMappings[newValue] || newValue;
        }

        const formattedOldValue = this.formatValue(oldValue);
        const formattedNewValue = this.formatValue(newValue);

        if (formattedOldValue !== formattedNewValue) {
          changes.push({
            key: this.fieldMappings[key] || key,
            oldValue: formattedOldValue,
            newValue: formattedNewValue
          });
        }
      });
      return changes;
    }

    if (!this.isObject(oldObj) && this.isObject(newObj)) {
      Object.keys(newObj).forEach(key => {
        let mappedNewValue: any = newObj[key];

        // Apply mappings when there is no old object (creation case)
        if (key === 'rfqItem_step') {
          mappedNewValue = this.stepMappings[mappedNewValue] || mappedNewValue;
        }

        if (key === 'rfqItem_active') {
          mappedNewValue = this.statusMappings[mappedNewValue] || mappedNewValue;
        }

        if (key === 'req_status') {
          mappedNewValue = this.reqStatusMappings[mappedNewValue] || mappedNewValue;
        }

        if (key === 'rfqItem_rfq_group') {
          mappedNewValue = this.rfqGroupMappings[mappedNewValue] || mappedNewValue;
        }

        const newValueFormatted = this.formatValue(mappedNewValue);
        if (newValueFormatted !== null && newValueFormatted !== undefined && newValueFormatted !== '') {
          changes.push({
            key: this.fieldMappings[key] || key,
            oldValue: 'N/A',
            newValue: newValueFormatted
          });
        }
      });
      return changes;
    }

    if (this.isObject(oldObj) && !this.isObject(newObj)) {
      Object.keys(oldObj).forEach(key => {
        changes.push({
          key: this.fieldMappings[key] || key,
          oldValue: this.formatValue(oldObj[key]),
          newValue: 'N/A'
        });
      });
      return changes;
    }

    if (oldObj !== newObj) {
      const key = log.element_id;
      let oldValue = oldObj;
      let newValue = newObj;
      if (key === 'rfqItem_step') {
        oldValue = this.stepMappings[oldValue] || oldValue;
        newValue = this.stepMappings[newValue] || newValue;
      }

      if (key === 'rfqItem_rfq_group') {
        oldValue = this.rfqGroupMappings[oldValue] || oldValue;
        newValue = this.rfqGroupMappings[newValue] || newValue;
      }
      return [{
        key: this.fieldMappings[key] || key,
        oldValue: this.formatValue(oldValue),
        newValue: this.formatValue(newValue)
      }];
    }

    return [];
  }

  isObject(value: any) {
    return typeof value === 'object' && value !== null && !Array.isArray(value);
  }

  formatValue(value: any): string {
    if (value === null || value === undefined) {
      return value;
    }
    if (typeof value === 'object') {
      if (value.title) return value.title;
      if (value.name) return value.name;
      if (value.RFQGroup_name) return value.RFQGroup_name;
      return 'Object';
    }
    const date = new Date(value);
    if (!isNaN(date.getTime()) && typeof value === 'string' && value.includes('-')) {
      return new Date(value).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
    }
    return String(value);
  }

  fetchCopyRelationship() {
    // Get current RFQItem to check if it was copied from another
    this.itemService.getRFQItemById({ rfqItem_id: this.data.ref_id }).subscribe({
      next: (res: any) => {
        try {
          if (res.status && res.data) {
            const copiedFromId = res.data.rfqItem_copied_from_id;

            if (!copiedFromId) {
              this.loadingCopyInfo = false;
              return;
            }

            // Fetch original product info directly from RFQItem table
            this.fetchOriginalProductInfo(copiedFromId);
          } else {
            this.loadingCopyInfo = false;
          }
        } catch (e) {
          this.loadingCopyInfo = false;
        }
      },
      error: () => {
        this.loadingCopyInfo = false;
      }
    });
  }

  private fetchOriginalProductInfo(copiedFromId: number) {
    this.itemService.getRFQItemById({ rfqItem_id: copiedFromId }).subscribe({
      next: (res: any) => {
        if (res.status && res.data) {
          const priceCode = res.data.rfqItem_style_number;
          this.copiedFromInfo = {
            id: copiedFromId,
            priceCode: priceCode || 'Price Code Unavailable',
            groupName: res.data?.RFQGroup?.RFQGroup_name || 'Group Unavailable'
          };
        } else {
          this.copiedFromInfo = {
            id: copiedFromId,
            priceCode: 'Price Code Unavailable'
          };
        }
        this.loadingCopyInfo = false;
      },
      error: () => {
        this.copiedFromInfo = {
          id: copiedFromId,
          priceCode: 'Price Code Unavailable'
        };
        this.loadingCopyInfo = false;
      }
    });
  }

  onClose(): void {
    this.dialogRef.close();
  }
}

