async function findRFQItemByPriceCode(priceCode) {
  return await sql.RFQItem.findOne({
    where: {
      rfqItem_style_number: priceCode
    }
  })
    .then(async (data) => {
      if (data) {
        return data.dataValues
      } else {
        return false
      }
    })
    .catch(err => {
      return false
    });
}

Customer.updateVendorData = async (req, result) => {
  let token = req.headers.authorization;
  let userInfo = await getUserInfo(token)
  let rfqItem = await findRFQItemByPriceCode(req.body.priceCode)
  let length = parseFloat(req.body.carton_length)
  let height = parseFloat(req.body.carton_height)
  let width = parseFloat(req.body.carton_width)
  let casePack = parseFloat(req.body.casePack)
  if (req.body.quote_accepted == true) {
    req.body.req_status = 2
  } else if (req.body.req_status == 1 || !req.body.Price) {
    req.body.req_status = 1
  }

  if (userInfo) {
    if (userInfo.role != 'vendor' && req.body['cbm_modified'] != true) {
      const rfqVendor = await sql.RFQVendor.findOne({
        where: {
          RFQVendor_id: req.body.quote_id
        }
      });
      if (rfqVendor) {
        await rfqVendor.update(
          {
          RFQVendor_cbm_pc: req.body['CBM/pc'],
          RFQVendor_amount: req.body.Price,
          RFQVendor_note: req.body.Note,
          quote_date: req.body.quote_date,
          lead_time: req.body['Lead Time (days)'],
          price_terms: req.body['Price Terms'],
          fob_country: req.body['FOB Country'],
          fob_port: req.body['FOB Port']
        }, { ref_id: rfqItem.rfqItem_id });
      }


      const rfqItemToUpdate = await sql.RFQItem.findOne({
        where: {
          rfqItem_id: rfqItem.rfqItem_id
        }
      });
      if (rfqItemToUpdate) {
        await rfqItemToUpdate.update({
          'rfqItem_cbm_per_price': req.body['CBM/pc'],
        }, { ref_id: rfqItem.rfqItem_id });
      }

      if (req.body.std_vendor_id_fk) {
        await updateSTDVendorPrice(req.body.std_vendor_id_fk, req.body.Price);
      }
      result(null, req.body);

    } else if (userInfo.role == 'vendor' || userInfo.role == 'admin' || userInfo.role == 'production') {

      if (length && height && width && req.body.casePack && req.body['cbm_modified'] == true) {
        req.body['CBM/pc'] = (((length * width * height) / 1000000) / casePack).toFixed(7);
      }

      const rfqVendor = await sql.RFQVendor.findOne({
        where: {
          RFQVendor_id: req.body.quote_id
        }
      });

      // A vendor may only edit their own factory's quote (prevents quote_id
      // enumeration). Internal roles and null-factory vendors pass through.
      if (rfqVendor && !vendorMayModifyQuote(userInfo, rfqVendor)) {
        return result(null, { status: 'forbidden' });
      }

      if (rfqVendor) {
        await rfqVendor.update({
          vendor_id_fk: req.body.Vendor.id,
          RFQVendor_amount: req.body.Price,
          RFQVendor_cbm_pc: req.body['CBM/pc'],
          RFQVendor_status: req.body.Status,
          RFQitem_id_fk: rfqItem.rfqItem_id,
          RFQVendor_note: req.body.Note,
          carton_width: req.body.carton_width,
          carton_height: req.body.carton_height,
          carton_length: req.body.carton_length,
          quote_date: req.body.quote_date,
          req_status: req.body.req_status,
          lead_time: req.body['Lead Time (days)'],
          price_terms: req.body['Price Terms'],
          fob_country: req.body['FOB Country'],
          fob_port: req.body['FOB Port'],
          // A fresh price from the vendor clears any pending re-quote request and
          // resets the auto-archive cycle: active again, opt-out cleared, fresh
          // quote_date means the 3-month clock starts over.
          requote_requested: false,
          RFQVendor_archived: false,
          RFQVendor_archive_optout: false
        }, { ref_id: rfqItem.rfqItem_id });
      }

      if (req.body.std_vendor_id_fk) {
        await updateSTDVendorPrice(req.body.std_vendor_id_fk, req.body.Price);
      }
      result(null, req.body);
    }
  } else {
    result(null, req.body);
  }
}

// Sourcing/admin flags a stale vendor quote for refresh. Sets requote_requested
// on the RFQVendor (leaving quote_date untouched so the "Quoted <date>" tooltip
// keeps showing the original date) and emails the factory to ask for a fresh price.
Customer.requestRequote = async (req, result) => {
  try {
    const token = req.headers.authorization;
    const userInfo = await getUserInfo(token);
    const allowedRoles = ['admin', 'sourcing_manager', 'production'];
    if (!userInfo || !allowedRoles.includes(userInfo.role)) {
      return result(null, { status: 'forbidden' });
    }

    const rfqVendor = await sql.RFQVendor.findOne({ where: { RFQVendor_id: req.body.quote_id } });
    if (!rfqVendor) {
      return result(null, { status: 'quote_not_found' });
    }

    // Re-requesting a price reactivates the item for the vendor: auto-unarchive and
    // clear the sticky opt-out so the 3-month cycle restarts once they answer.
    await rfqVendor.update(
      { requote_requested: true, RFQVendor_archived: false, RFQVendor_archive_optout: false },
      { ref_id: rfqVendor.RFQitem_id_fk }
    );

    // Resolve the priceCode (style number) for the email — prefer the client-sent
    // value, fall back to the RFQItem the quote belongs to.
    let priceCode = req.body.priceCode;
    if (!priceCode) {
      const rfqItem = await sql.RFQItem.findOne({ where: { rfqItem_id: rfqVendor.RFQitem_id_fk } });
      priceCode = rfqItem ? rfqItem.rfqItem_style_number : null;
    }
    // RFQVendor.vendor_id_fk stores Factory.id (see reqVendor), which is what
    // emailVendorsForFactory expects.
    if (priceCode && rfqVendor.vendor_id_fk) {
      await emailVendorsForFactory(rfqVendor.vendor_id_fk, priceCode);
    }

