const { Op } = require('sequelize');

const CACHE_TTL_MS = 5 * 60 * 1000;

const RFQ_LIST_ITEM_EXCLUDE_ATTRIBUTES = [
  'rfqItem_auditlog',
  'rfqItem_default_cbm',
  'rfqItem_gen_fob_netsell',
  'rfqItem_gen_whse_netsell',
  'rfqItem_gen_poe_netsell',
  'rfqItem_gen_mddp_netsell',
  'rfqItem_gen_ldp_margin',
  'rfqItem_cbm_per_piece',
  'rfqItem_quote_update',
  'rfqItem_price_per_cbm',
  'rfqItem_standardized_products',
];

const RFQ_VENDOR_LIST_ATTRIBUTES = [
  'RFQVendor_id',
  'RFQVendor_amount',
  'RFQVendor_cbm_pc',
  'RFQVendor_status',
  'RFQitem_id_fk',
  'RFQVendor_note',
  'carton_width',
  'carton_height',
  'carton_length',
  'req_status',
  'vendor_id_fk',
  'quote_date',
  'std_vendor_id_fk',
  'lead_time',
  'price_terms',
  'fob_country',
  'fob_port',
  'requote_requested',
  'RFQVendor_archived',
  'RFQVendor_archive_optout',
];

const FACTORY_LIST_ATTRIBUTES = [
  'id',
  'factory_name',
  'factory_nickname',
  'factory_status',
  'factory_access',
  'factory_country',
  'sort_order',
];

let merchGroupCache = { rows: null, expiresAt: 0 };
let whsePriceCache = { value: null, expiresAt: 0 };

function buildMerchGroupMap(merchGroupData) {
  const map = new Map();
  if (!merchGroupData) {
    return map;
  }
  for (const row of merchGroupData) {
    const values = row.dataValues || row;
    const mgId = values.mg_id;
    if (mgId != null && mgId !== '') {
      map.set(String(mgId), values);
    }
  }
  return map;
}

/** Resolve merch group id to grid cell value. Never embed the full merchGroup list in JSON. */
function resolveMerchGroupValue(merchGroupMap, id) {
  if (id == null || id === '') {
    return null;
  }
  const mg = merchGroupMap.get(String(id));
  if (mg) {
    const values = mg.dataValues || mg;
    return { title: values.mg_desc, mg_code: values.mg_code, id: values.mg_id };
  }
  return { data: id };

