async function makeSingleToken(email) {
  return await sql.vendor.findOne({
    where: {
      vendor_email: email
    }
  })
    .then(async (data) => {
      if (data) {
        // Create token
        let token = jwt.sign(
          { name: data.vendor_name, user_id: data.vendor_id, email, role: 'vendor', access: data.dataValues.vendor_access, factory_id: data.dataValues.factory_id_fk }, privateKey,
          {
            algorithm: 'RS256',
            expiresIn: "24h",
          }
        );
        return token
      } else {
        return false
      }
    })
    .catch(err => {
      return false
    });
}

Customer.addingNewVendor = async (req, result) => {
	let data = req.body;
	let createdQuotes = [];
	for (var i = 0; data.length > i; i++) {
		let rfqItem = await findRFQItemByPriceCode(data[i].priceCode)
		let vendorRecord = await sql.RFQVendor.create({
			vendor_id_fk: data[i].id, RFQVendor_amount: null, RFQVendor_cbm_pc: null, RFQVendor_status: null, RFQitem_id_fk: rfqItem.rfqItem_id, quote_date: new Date().toISOString()
		})
			.catch(err => {
				result(err, null);
			});
		if (vendorRecord) {
			createdQuotes.push({
				vendor_id: data[i].id,
				quote_id: vendorRecord.RFQVendor_id
			});
		}
	}
	result(null, createdQuotes);
}

