ngOnInit() {
  // Resolve which audit table + DB column the clicked colId maps to. Without a
  // mapping we cannot show a meaningful per-column history, so bail to an empty
  // (but well-formed) table rather than silently showing the wrong column.
  const ctx = AUDIT_FIELD_MAP[this.data.moduleName];
  const dbField = ctx?.fields?.[this.data.colId];

  if (!ctx || !dbField) {
    this.dataSource = new MatTableDataSource<logData>([]);
    this.dataSource.paginator = this.paginator;
    this.dataSource.sort = this.sort;
    return;
  }

  const auditModule = ctx.module;
  const isVendorScoped = auditModule === 'RFQVendor';
  // The detail (vendor) view shares one ref_id (parent rfqItem) across every
  // quote line, so we must narrow to the specific RFQVendor_id; null means
  // "no quote id supplied" — show all rather than nothing.
  const quoteId = this.data.quote_id != null ? Number(this.data.quote_id) : null;

  this.itemService.getAuditLog({ ref_id: this.data.ref_id, moduleName: auditModule, isPriceLog: true })
    .subscribe((res: any) => {
      if (res.status != 200) {
        return;
      }

      let transformedData = res.data
        .map((row: any) => {
          let oldObj: any = {};
          let newObj: any = {};
          try {
            oldObj = row.oldValue ? JSON.parse(row.oldValue) : {};
            newObj = row.newValue ? JSON.parse(row.newValue) : {};
          } catch (e) {
          }
          return {
            username: row.username,
            oldObj,
            newObj,
            oldValue: this.readField(oldObj, dbField),
            newValue: this.readField(newObj, dbField),
            actionDate: row.actionDate
          };
        })
        // For vendor-scoped logs, keep only the quote line the user clicked.
        .filter(row => {
          if (!isVendorScoped || quoteId == null) return true;
          const rowQuoteId = row.newObj?.RFQVendor_id ?? row.oldObj?.RFQVendor_id ?? null;
          return rowQuoteId != null && Number(rowQuoteId) === quoteId;
        })
        // Keep only rows where THIS column actually changed.
        .filter(row => row.oldValue !== row.newValue);

      // Deduplicate consecutive same values per user (avoids noise from
      // multi-field saves that re-write the same value).
      transformedData = transformedData.filter((item, index, arr) => {
        if (index === 0) return true;
        const prev = arr[index - 1];
        return !(prev.username === item.username && prev.newValue === item.newValue);
      });

      // Sort by date (newest first), then username for stable ordering.
      transformedData.sort((a, b) => {
        const dateA = new Date(a.actionDate).getTime();
        const dateB = new Date(b.actionDate).getTime();
        if (dateB !== dateA) return dateB - dateA;
        return (a?.username ?? '').localeCompare(b?.username ?? '');
      });

      this.dataSource = new MatTableDataSource(transformedData);
      this.dataSource.sortingDataAccessor = (row: any, sortHeaderId: string) => {
        switch (sortHeaderId) {
          case 'Name':
            return row.username ?? '';
          case 'Date':
            return new Date(row.actionDate).getTime();
          case 'newValue':
            return row.newValue ?? '';
          case 'oldValue':
            return row.oldValue ?? '';
          default:
            return '';
        }
      };
      this.dataSource.paginator = this.paginator;
      this.dataSource.sort = this.sort;
    });
}

/**
 * Reads one DB column out of a parsed audit-row object, normalising to a
 * comparable/displayable value. Returns null for absent/blank so "no value"
 * rows compare equal and render as '—'.
 */
private readField(obj: any, dbField: string): any {
  const raw = obj?.[dbField];
  if (raw === undefined || raw === null || raw === '') {
    return null;
  }
  // Numeric columns can come back as strings ("12.50") or numbers; compare by
  // numeric value when possible so trailing-zero/format churn isn't shown as a change.
  const num = Number(raw);
  return Number.isNaN(num) ? raw : num;
}

