import { describe, expect, test, jest } from '@jest/globals';
import { readFileSync } from 'fs';
import { join } from 'path';
import { DetailCellRenderer } from './detail-cell-renderer.component';

describe('DetailCellRenderer - sales access guardrails', () => {
  function getConfigJson(): any {
    const configPath = join(process.cwd(), 'src', 'assets', 'config.json');
    return JSON.parse(readFileSync(configPath, 'utf8'));
  }

  function createComponent() {
    const configJson = getConfigJson();
    const dialogMock = { open: jest.fn() } as any;
    const itemServiceMock = { getFOBCountry: jest.fn(() => ({ subscribe: jest.fn() })) } as any;
    const snackBarMock = { open: jest.fn() } as any;
    const equationMock = {} as any;
    const configServiceMock = { get: jest.fn((key: string) => configJson?.[key]) } as any;
    const authServiceMock = { getUserFromToken: jest.fn(() => Promise.resolve({ user_id: 21 })) } as any;
    const loaderServiceMock = { increment: jest.fn(), decrement: jest.fn() } as any;

    const aiSettingsMock = { getFactoryCountryMap: jest.fn(() => ({ subscribe: jest.fn() })) } as any;
    const component = new DetailCellRenderer(
      dialogMock,
      itemServiceMock,
      snackBarMock,
      equationMock,
      configServiceMock,
      authServiceMock,
      loaderServiceMock,
      aiSettingsMock,
    );

    return { component };
  }

  test('allowAccessToSalesUsers config stays pinned', () => {
    const { component } = createComponent();
    const c = component as any;
    c.allowAccessToSalesUsers = (c.configService.get('allowAccessToSalesUsers') as number[]) || [];

