import { describe, expect, test, jest, beforeEach } from '@jest/globals';
import { of } from 'rxjs';
import { AuditLogComponent } from './auditLog.component';

/**
 * "Log History" (AuditLogComponent) must show the change history of the COLUMN
 * the user clicked — not a hardcoded vendor price. These tests pin the
 * column-aware behaviour for both call sites:
 *   - master grid  (moduleName 'rfq')        → RFQItem rows, rfqItem_* columns
 *   - vendor detail (moduleName 'rfq_detail') → RFQVendor rows, RFQVendor_* columns
 */
describe('AuditLogComponent - per-column Log History', () => {
  let getAuditLog: jest.Mock<any>;

  function row(oldObj: any, newObj: any, username = 'alice', actionDate = '2026-06-20T10:00:00Z') {
    return {
      username,
      actionDate,
      oldValue: oldObj == null ? null : JSON.stringify(oldObj),
      newValue: newObj == null ? null : JSON.stringify(newObj),
    };
  }

  function createComponent(data: any, rows: any[]) {
    getAuditLog = jest.fn(() => of({ status: 200, data: rows })) as any;
    const itemServiceMock = { getAuditLog } as any;
    const dialogRefMock = { close: jest.fn() } as any;
    const dialogMock = {} as any;
    const snackBarMock = { open: jest.fn() } as any;
    const fbMock = {} as any;
    const component = new AuditLogComponent(itemServiceMock, dialogRefMock, data, dialogMock, snackBarMock, fbMock);
    return component;
  }

  test('master grid: extracts the clicked rfqItem_* column and queries a single module', () => {
    const c = createComponent(
      { colId: 'freight', ref_id: 42, moduleName: 'rfq' },
      [
        row({ rfqItem_freight: '1.00', rfqItem_wholesale: '9' }, { rfqItem_freight: '2.00', rfqItem_wholesale: '9' }),
        // wholesale changed but freight did not -> must be filtered out
        row({ rfqItem_freight: '2.00', rfqItem_wholesale: '9' }, { rfqItem_freight: '2.00', rfqItem_wholesale: '15' }),
      ],
    );
    c.ngOnInit();

    expect(getAuditLog).toHaveBeenCalledWith({ ref_id: 42, moduleName: 'RFQItem', isPriceLog: true });
    const data = c.dataSource.data as any[];
    expect(data.length).toBe(1);
    expect(data[0].oldValue).toBe(1);
    expect(data[0].newValue).toBe(2);
  });

  test('vendor detail: extracts RFQVendor_amount and narrows to the clicked quote line', () => {
    const c = createComponent(
      { colId: 'price', ref_id: 42, moduleName: 'rfq_detail', quote_id: 100 },
      [
        // our quote line (RFQVendor_id 100) — should appear
        row({ RFQVendor_id: 100, RFQVendor_amount: '5' }, { RFQVendor_id: 100, RFQVendor_amount: '6' }),
        // a different vendor's quote on the same item — must be excluded
        row({ RFQVendor_id: 200, RFQVendor_amount: '50' }, { RFQVendor_id: 200, RFQVendor_amount: '60' }),
      ],
    );
    c.ngOnInit();

    expect(getAuditLog).toHaveBeenCalledWith({ ref_id: 42, moduleName: 'RFQVendor', isPriceLog: true });
    const data = c.dataSource.data as any[];
    expect(data.length).toBe(1);
    expect(data[0].oldValue).toBe(5);
    expect(data[0].newValue).toBe(6);
  });

  test('vendor detail: note column reads RFQVendor_note, not price', () => {
    const c = createComponent(
      { colId: 'note', ref_id: 42, moduleName: 'rfq_detail', quote_id: 100 },
      [
        row(
          { RFQVendor_id: 100, RFQVendor_amount: '5', RFQVendor_note: 'old note' },
          { RFQVendor_id: 100, RFQVendor_amount: '6', RFQVendor_note: 'new note' },
        ),
      ],
    );
    c.ngOnInit();

    const data = c.dataSource.data as any[];
    expect(data.length).toBe(1);
    expect(data[0].oldValue).toBe('old note');
    expect(data[0].newValue).toBe('new note');
  });

  test('unknown colId yields an empty table and does not query the backend', () => {
    const c = createComponent({ colId: 'totally_unknown', ref_id: 42, moduleName: 'rfq' }, []);
    c.ngOnInit();

    expect(getAuditLog).not.toHaveBeenCalled();
    expect(c.dataSource.data.length).toBe(0);
  });

  test('numeric format churn (trailing zeros) is not reported as a change', () => {
    const c = createComponent(
      { colId: 'freight', ref_id: 42, moduleName: 'rfq' },
      [row({ rfqItem_freight: '2' }, { rfqItem_freight: '2.00' })],
    );
    c.ngOnInit();

    expect((c.dataSource.data as any[]).length).toBe(0);
  });
});

